@* Manages wizard step navigation and holds the shared Order state. *@

@if (_step == 1)
{
    <ShippingStep Shipping="@_order.Shipping" OnNext="@GoToPayment" />
}
else
{
    <PaymentStep Payment="@_order.Payment"
                 OnBack="@GoToShipping"
                 OnPlaceOrder="@PlaceOrder" />
}

@code {
    /// <summary>Raised when the user completes checkout with a fully-validated order.</summary>
    [Parameter] public EventCallback<Order> OnOrderPlaced { get; set; }

    private readonly Order _order = new();
    private int _step = 1;

    private void GoToPayment()
    {
        _step = 2;
    }

    private void GoToShipping()
    {
        _step = 1;
    }

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@implements IDisposable
@inject IAddressValidator AddressValidator

<h3>Shipping Information</h3>

<label>
    Name
    <input @bind="Shipping.Name" @bind:event="oninput" disabled="@_isValidating" />
</label>

<label>
    Address
    <input @bind="Shipping.Address" @bind:event="oninput" @oninput="OnFieldChanged" disabled="@_isValidating" />
</label>

<label>
    City
    <input @bind="Shipping.City" @bind:event="oninput" @oninput="OnFieldChanged" disabled="@_isValidating" />
</label>

<label>
    Zip Code
    <input @bind="Shipping.ZipCode" @bind:event="oninput" @oninput="OnFieldChanged" disabled="@_isValidating" />
</label>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <p class="error">@_errorMessage</p>
}

<button disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    [Parameter, EditorRequired] public ShippingInfo Shipping { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _errorMessage;
    private bool _disposed;

    /// <summary>
    /// Marks any prior validation stale so the next click starts fresh.
    /// </summary>
    private void OnFieldChanged()
    {
        _errorMessage = null;
        CancelPendingValidation();
    }

    private async Task ValidateAndProceed()
    {
        // Cancel any in-flight validation (user clicked Next again, or fields changed).
        CancelPendingValidation();

        if (string.IsNullOrWhiteSpace(Shipping.Address) ||
            string.IsNullOrWhiteSpace(Shipping.City) ||
            string.IsNullOrWhiteSpace(Shipping.ZipCode))
        {
            _errorMessage = "Address, City, and Zip Code are required.";
            return;
        }

        _cts = CancellationTokenSource.CreateLinkedTokenSource(default);
        var token = _cts.Token;

        _isValidating = true;
        _errorMessage = null;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            if (token.IsCancellationRequested)
                return;

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when the component is disposed or fields changed mid-validation.
        }
        catch (Exception)
        {
            if (!token.IsCancellationRequested)
            {
                _errorMessage = "Address validation failed. Please try again.";
            }
        }
        finally
        {
            // Only update UI state if this is still the active validation.
            if (!_disposed && !token.IsCancellationRequested)
            {
                _isValidating = false;
            }
        }
    }

    private void CancelPendingValidation()
    {
        if (_cts is not null)
        {
            _cts.Cancel();
            _cts.Dispose();
            _cts = null;
            _isValidating = false;
        }
    }

    public void Dispose()
    {
        _disposed = true;
        CancelPendingValidation();
    }
}

